export const buildAuth = () => betterAuth({
    databaseHooks: {
        user: {
            create: {
                after: async (user) => {
                    await ensureOrgMembership(db, user.id);
                    await signupHooks.run(user);
                    await platformEvents.emit('user_signed_up', { userId: user.id });
                },
            },
        },
    },
});
